window.ASBAB_NUZUL_CACHE["14"] = {"mapping_ayat":{"14:5":[{"p":"Ahmad","n":2921,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْجَعْفِيُّ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ تَبَارَكَ وَتَعَالَى{ وَذَكِّرْهُمْ بِأَيَّامِ اللَّهِ }قَالَ بِنِعَمِ اللَّهِ تَبَارَكَ وَتَعَالَىحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيٍّ نَحْوَهُ وَلَمْ يَرْفَعْهُ","trj":"Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Yahya bin Abdullah] mantan budak Bani Hasim, telah meriwayatkan kepada kami [Muhammad bin Aban Al Ja'fi] dari [Abu lshaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, tentang firman Allah Tabaaraka Wa Ta'ala: '(dan ingatkanlah mereka kepada hari-hari Allah) ' (QS Ibrahim: 5) beliau bersabda: \"Yaitu dengan nikmat-nikmat Allah Tabaaraka Wa Ta'ala.\" Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Abu Abdullah Al Anbari] dia berkata, telah menceritakan kepada kami [Abul Walid At Thayalisi] dia berkata, telah menceritakan kepada kami [Muhammad bin Abban] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay] dengan hadits yang semakna, namun ia tidak memarfu'kannya (tidak sampai kepada Nabi).\""}],"14:14":[{"p":"Nasa'i","n":1984,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ خَيْثَمَةَ عَنْ الْبَرَاءِ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [bapaknya] dari [Khaitsamah] dari [Al Barra'] dia berkata; \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Dia berkata; 'Ayat ini turun menerangkan tentang siksa kubur.'"},{"p":"Nasa'i","n":1985,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَدِينِي دِينُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Al Barra' bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Beliau bersabda: 'Ayat ini turun menerangkan tentang siksa kubur.' Dikatakan kepadanya; \"Siapakah Rabbmu?\" lalu ia menjawab, \"Rabbku Allah dan agamaku adalah agamanya Nabi Muhammad shallallahu 'alaihi wasallam.\" Maka itulah yang sesuai dengan firman-Nya, \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27)"}],"14:27":[{"p":"Abu Dawud","n":3972,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُسْلِمَ إِذَا سُئِلَ فِي الْقَبْرِ فَشَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }","trj":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Alqamah bin Martsad] dari [Sa'd bin Ubaidah] dari [Al Bara bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang muslim ditanya dalam kubur, lalu ia bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, dan Muhammad shallallahu 'alaihi wasallam adalah utusan Allah. Maka itu adalah bukti dari firman Allah Azza Wa Jalla: (Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh…) -Qs. Ibrahim: 27-"},{"p":"Abu Dawud","n":3974,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَهَذَا لَفْظُ هَنَّادٍ عَنْ الْأَعْمَشِ عَنْ الْمِنْهَالِ عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةِ رَجُلٍ مِنْ الْأَنْصَارِ فَانْتَهَيْنَا إِلَى الْقَبْرِ وَلَمَّا يُلْحَدْ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَلَسْنَا حَوْلَهُ كَأَنَّمَا عَلَى رُءُوسِنَا الطَّيْرُ وَفِي يَدِهِ عُودٌ يَنْكُتُ بِهِ فِي الْأَرْضِ فَرَفَعَ رَأْسَهُ فَقَالَ اسْتَعِيذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ مَرَّتَيْنِ أَوْ ثَلَاثًا زَادَ فِي حَدِيثِ جَرِيرٍ هَاهُنَا وَقَالَ وَإِنَّهُ لَيَسْمَعُ خَفْقَ نِعَالِهِمْ إِذَا وَلَّوْا مُدْبِرِينَ حِينَ يُقَالُ لَهُ يَا هَذَا مَنْ رَبُّكَ وَمَا دِينُكَ وَمَنْ نَبِيُّكَ قَالَ هَنَّادٌ قَالَ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ دِينِيَ الْإِسْلَامُ فَيَقُولَانِ لَهُ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ قَالَ فَيَقُولُ هُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولَانِ وَمَا يُدْرِيكَ فَيَقُولُ قَرَأْتُ كِتَابَ اللَّهِ فَآمَنْتُ بِهِ وَصَدَّقْتُ زَادَ فِي حَدِيثِ جَرِيرٍ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }الْآيَةُ ثُمَّ اتَّفَقَا قَالَ فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ قَدْ صَدَقَ عَبْدِي فَأَفْرِشُوهُ مِنْ الْجَنَّةِ وَافْتَحُوا لَهُ بَابًا إِلَى الْجَنَّةِ وَأَلْبِسُوهُ مِنْ الْجَنَّةِ قَالَ فَيَأْتِيهِ مِنْ رَوْحِهَا وَطِيبِهَا قَالَ وَيُفْتَحُ لَهُ فِيهَا مَدَّ بَصَرِهِ قَالَ وَإِنَّ الْكَافِرَ فَذَكَرَ مَوْتَهُ قَالَ وَتُعَادُ رُوحُهُ فِي جَسَدِهِ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ هَاهْ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ كَذَبَ فَأَفْرِشُوهُ مِنْ النَّارِ وَأَلْبِسُوهُ مِنْ النَّارِ وَافْتَحُوا لَهُ بَابًا إِلَى النَّارِ قَالَ فَيَأْتِيهِ مِنْ حَرِّهَا وَسَمُومِهَا قَالَ وَيُضَيَّقُ عَلَيْهِ قَبْرُهُ حَتَّى تَخْتَلِفَ فِيهِ أَضْلَاعُهُ زَادَ فِي حَدِيثِ جَرِيرٍ قَالَ ثُمَّ يُقَيَّضُ لَهُ أَعْمَى أَبْكَمُ مَعَهُ مِرْزَبَّةٌ مِنْ حَدِيدٍ لَوْ ضُرِبَ بِهَا جَبَلٌ لَصَارَ تُرَابًا قَالَ فَيَضْرِبُهُ بِهَا ضَرْبَةً يَسْمَعُهَا مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ إِلَّا الثَّقَلَيْنِ فَيَصِيرُ تُرَابًا قَالَ ثُمَّ تُعَادُ فِيهِ الرُّوحُحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا الْمِنْهَالُ عَنْ أَبِي عُمَرَ زَاذَانَ قَالَ سَمِعْتُ الْبَرَاءَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hannad As Sari] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] - dan ini adalah lafadz Hannad- dari [Al A'masy] dari [Al Minhal] dari [Zadzan] dari [Al Bara bin Azib] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam keluar untuk melihat jenazah seorang laki-laki Anshar, kami pun tiba di pemakaman. Ketika lubang lahad telah dibuat, Rasulullah shallallahu 'alaihi wasallam duduk, lalu kami ikut duduk di sisinya. Kami diam, seakan-akan di atas kepala kami ada burung. Saat itu beliau memegang sebatang kayu yang ditancapkan ke dalam tanah, beliau lalu mengangkat kepalanya dan bersabda: \"Mintalah perlindungan kepada Allah dari siksa kubur.\" Beliau ucapkan kalimat itu hingga dua atau tiga kali. Demikanlah tambahan dalam hadits Jarir. Beliau melanjutkan: \"Sungguh, mayat itu akan dapat mendengar derap sandal mereka saat berlalau pulang; yakni ketika ditanyakan kepadanya, 'Wahai kamu, siapa Rabbmu? Apa agamamu? Dan siapa Nabimu? ' -Hannad menyebutkan; Beliau bersabda: - \"lalu ada dua malaikat mendatanginya seranya mendudukkannya. Malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Rabbku adalah Allah.\" Malaikat itu bertanya lagi, \"Apa agamamu?\" ia menjawab, \"Agamaku adalah Islam.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Dia adalah Rasulullah shallallahu 'alaihi wasallam.\" malaikat itu bertanya lagi, \"Apa yang kamu ketahui?\" ia menjawab, \"Aku membaca Kitabullah, aku mengimaninya dan membenarkannya.\" Dalam hadits Jarir ditambahkan, \"Maka inilah makna firman Allah: '(Allah meneguhkan (iman) orang-orang yang beriman…) ' hingga akhir ayat. -Qs. Ibrahim: 27- kemudian kedua perawi sepakat pada lafadz, \"Beliau bersabda: \"Kemudian ada suara dari langit yang menyeru, \"Benarlah apa yang dikatakan oleh hamba-Ku, hamparkanlah permadani untuknya di surga, bukakan baginya pintu-pintu surga dan berikan kepadanya pakaian surga.\" beliau melanjutkan: \"Kemudian didatangkan kepadanya wewangian surga, lalu kuburnya diluaskan sejauh mata memandang.\" Beliau melanjutkan: \"Jika yang meninggal adalah orang kafir, maka ruhnya akan dikembalikan kepada jasadnya. Saat itu datanglah dua malaikat serya mendudukkannya. Kedua malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Hah, hah, hah. Aku tidak tahu.\" Malaikat itu bertanya, \"Apa agamamu?\" ia menjawab, \"Hah, hah. Aku tidak tahu.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Hah, hah. Aku tidak tahu.\" Setelah itu terdengar suara dari langit: \"Ia telah berdusta. Berilah ia hamparan permadani dari neraka, berikan pakaian dari neraka, dan bukakanlah pintu-pintu neraka untuknya.\" Beliau melanjutkan: \"Kemudian didatangkan kepadanya panas dan baunya neraka. Lalu kuburnya disempitkan hingga tulangnya saling berhimpitan.\" Dalam hadits Jarir ditambahkan, \"Beliau bersabda: \"Lalu ia dibelenggu dalam keadaan buta dan bisu. Dan baginya disediakan sebuah pemukul dari besi, sekiranya pemukul itu dipukulkan pada sebuah gunung niscaya akan menjadi debu.\" Beliau melanjutkan: \"Laki-laki kafir itu kemudian dipukul dengan pemukul tersebut hingga suaranya dapat didengar oleh semua makhluk; dari ujung timur hingga ujung barat -kecuali jin dan manusia- hingga menjadi debu.\" Beliau meneruskan ceritanya: \"Setelah itu, ruhnya dikembalikan lagi.\" Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada kami [Al Minhal] dari [Abu Umar Zadzan] ia berkata; Aku mendengar [Al Bara] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda…. lalu ia menyebutkan seperti hadits tersebut.\""},{"p":"Ahmad","n":2105,"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ عَلْقَمَةُ بْنُ مَرْثَدٍ قَالَ أَخْبَرَنِي عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنِ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْقَبْرِ إِذَا سُئِلَ فَعَرَفَ رَبَّهُ قَالَ وَقَالَ شَيْءٌ لَا أَحْفَظُهُ فَذَلِكَ قَوْلُهُ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] ia berkata, [Alqamah bin Martsad], ia berkata; telah mengabarkan kepadaku dari [Sa'ad bin Ubaidah] dari [Al Baraa` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam bersabda berkenaan dengan kubur: \"Jika seorang hamba ditanya, kemudian ia mengetahui Rabb-nya, -kemudian beliau mengatakan sesuatu namun saya tidak menghafalnya- dan itulah yang termaktub dalam firman Allah: 'Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat. (QS. Ibrahim 27).'\""},{"p":"Bukhari","n":1280,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقْعِدَ الْمُؤْمِنُ فِي قَبْرِهِ أُتِيَ ثُمَّ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ بِهَذَا وَزَادَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }نَزَلَتْ فِي عَذَابِ الْقَبْرِ","trj":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'ad bin 'Ubadah] dari [Al Bara' bin 'Azib radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Apabila (jenazah) seorang muslim sudah didudukkan dalam kuburnya maka dia akan dihadapkan (pertanyaan malaikat), kemudian ia bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Allah dan Muhammad utusan Allah. Itulah perkataan seorang muslim sebagaimana firman Allah subhanahu wata'ala (QS Ibrahim ayat 27 yang artinya): (\"Allah akan meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu\"). Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] seperti riwayat ini lalu menambahkannya (firman Allah subhanahu wata'ala): (\"Allah akan meneguhkan (iman) orang-orang yang beriman…\") ayat ini turun berkenaan dengan masalah siksa kubur\"."},{"p":"Nasa'i","n":1984,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ خَيْثَمَةَ عَنْ الْبَرَاءِ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [bapaknya] dari [Khaitsamah] dari [Al Barra'] dia berkata; \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Dia berkata; 'Ayat ini turun menerangkan tentang siksa kubur.'"},{"p":"Nasa'i","n":1985,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَدِينِي دِينُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Al Barra' bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Beliau bersabda: 'Ayat ini turun menerangkan tentang siksa kubur.' Dikatakan kepadanya; \"Siapakah Rabbmu?\" lalu ia menjawab, \"Rabbku Allah dan agamaku adalah agamanya Nabi Muhammad shallallahu 'alaihi wasallam.\" Maka itulah yang sesuai dengan firman-Nya, \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27)"}],"14:36":[{"p":"Muslim","n":294,"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا قَوْلَ اللَّهِ عَزَّ وَجَلَّ فِي إِبْرَاهِيمَ{ رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِنْ النَّاسِ فَمَنْ تَبِعَنِي فَإِنَّهُ مِنِّي }الْآيَةَ وَقَالَ عِيسَى عَلَيْهِ السَّلَام{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }فَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ أُمَّتِي أُمَّتِي وَبَكَى فَقَالَ اللَّهُ عَزَّ وَجَلَّ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ وَرَبُّكَ أَعْلَمُ فَسَلْهُ مَا يُبْكِيكَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَسَأَلَهُ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَالَ وَهُوَ أَعْلَمُ فَقَالَ اللَّهُ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ فَقُلْ إِنَّا سَنُرْضِيكَ فِي أُمَّتِكَ وَلَا نَسُوءُكَ","trj":"Telah menceritakan kepada kami [Yunus bin Abdul A'la ash-Shadafi] telah mengabarkan kepada kami [Ibnu Wahb] dia berkata, telah mengabarkan kepada kami [Amru bin al-Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya dari [Abdurrahman bin Jubair] dari [Abdullah bin Amr bin al-'Ash] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca firman Allah mengenai Ibrahim: '(Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, Maka Sesungguhnya orang itu termasuk golonganku) ' (Qs. Ibrahim: 36) hingga akhir ayat. Dan mengenai Isa Alaihissalam: '(Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana) ' (Qs. Al Maidah: 118), kemudian beliau mengangkat kedua tangannya seraya berdo'a: \"Ya Allah, selamatkanlah umatku, selamatkanlah umatku, \" dengan bercucuran air mata. Kemudian Allah 'azza wajalla berkata kepada malaikat Jibril: \"Temuilah Muhammad -dan Rabbmulah yang lebih tahu- dan tanyakan kepadanya, 'Apa yang membuatmu menangis? ' Maka malaikat Jibril pun bertanya kepada beliau, dan beliau shallallahu 'alaihi wasallam menjawabnya dengan apa yang dikatakan Allah-dan Allah lebih mengetahui hal itu-. Kemudian Allah berkata: 'Wahai Jibril, temuilah Muhammad dan katakan bahwa Kami akan membuatmu senang dengan umatmu dan tidak akan membuatmu sedih karenanya (Kami akan menyelamatkan semua umatmu-pent) '.\""}],"14:48":[{"p":"Muslim","n":465,"ar":"حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ وَهُوَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ يَعْنِي أَخَاهُ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي أَبُو أَسْمَاءَ الرَّحَبِيُّ أَنَّ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ قَالَكُنْتُ قَائِمًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ حِبْرٌ مِنْ أَحْبَارِ الْيَهُودِ فَقَالَ السَّلَامُ عَلَيْكَ يَا مُحَمَّدُ فَدَفَعْتُهُ دَفْعَةً كَادَ يُصْرَعُ مِنْهَا فَقَالَ لِمَ تَدْفَعُنِي فَقُلْتُ أَلَا تَقُولُ يَا رَسُولَ اللَّهِ فَقَالَ الْيَهُودِيُّ إِنَّمَا نَدْعُوهُ بِاسْمِهِ الَّذِي سَمَّاهُ بِهِ أَهْلُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اسْمِي مُحَمَّدٌ الَّذِي سَمَّانِي بِهِ أَهْلِي فَقَالَ الْيَهُودِيُّ جِئْتُ أَسْأَلُكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَنْفَعُكَ شَيْءٌ إِنْ حَدَّثْتُكَ قَالَ أَسْمَعُ بِأُذُنَيَّ فَنَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُودٍ مَعَهُ فَقَالَ سَلْ فَقَالَ الْيَهُودِيُّ أَيْنَ يَكُونُ النَّاسُ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَوَاتُ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ فِي الظُّلْمَةِ دُونَ الْجِسْرِ قَالَ فَمَنْ أَوَّلُ النَّاسِ إِجَازَةً قَالَ فُقَرَاءُ الْمُهَاجِرِينَ قَالَ الْيَهُودِيُّ فَمَا تُحْفَتُهُمْ حِينَ يَدْخُلُونَ الْجَنَّةَ قَالَ زِيَادَةُ كَبِدِ النُّونِ قَالَ فَمَا غِذَاؤُهُمْ عَلَى إِثْرِهَا قَالَ يُنْحَرُ لَهُمْ ثَوْرُ الْجَنَّةِ الَّذِي كَانَ يَأْكُلُ مِنْ أَطْرَافِهَا قَالَ فَمَا شَرَابُهُمْ عَلَيْهِ قَالَ مِنْ عَيْنٍ فِيهَا تُسَمَّى سَلْسَبِيلًا قَالَ صَدَقْتَ قَالَ وَجِئْتُ أَسْأَلُكَ عَنْ شَيْءٍ لَا يَعْلَمُهُ أَحَدٌ مِنْ أَهْلِ الْأَرْضِ إِلَّا نَبِيٌّ أَوْ رَجُلٌ أَوْ رَجُلَانِ قَالَ يَنْفَعُكَ إِنْ حَدَّثْتُكَ قَالَ أَسْمَعُ بِأُذُنَيَّ قَالَ جِئْتُ أَسْأَلُكَ عَنْ الْوَلَدِ قَالَ مَاءُ الرَّجُلِ أَبْيَضُ وَمَاءُ الْمَرْأَةِ أَصْفَرُ فَإِذَا اجْتَمَعَا فَعَلَا مَنِيُّ الرَّجُلِ مَنِيَّ الْمَرْأَةِ أَذْكَرَا بِإِذْنِ اللَّهِ وَإِذَا عَلَا مَنِيُّ الْمَرْأَةِ مَنِيَّ الرَّجُلِ آنَثَا بِإِذْنِ اللَّهِ قَالَ الْيَهُودِيُّ لَقَدْ صَدَقْتَ وَإِنَّكَ لَنَبِيٌّ ثُمَّ انْصَرَفَ فَذَهَبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ سَأَلَنِي هَذَا عَنْ الَّذِي سَأَلَنِي عَنْهُ وَمَا لِي عِلْمٌ بِشَيْءٍ مِنْهُ حَتَّى أَتَانِيَ اللَّهُ بِهِو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ كُنْتُ قَاعِدًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ زَائِدَةُ كَبِدِ النُّونِ وَقَالَ أَذْكَرَ وَآنَثَ وَلَمْ يَقُلْ أَذْكَرَا وَآنَثَا","trj":"Telah menceritakan kepada kami [al-Hasan bin Ali al-Hulwani] telah menceritakan kepada kami [Abu Taubah, yaitu ar-Rabi' bin Nafi'] telah menceritakan kepada kami [Mua'wiyah, yaitu Ibnu Sallam] dari [Zaid, yaitu saudaranya] bahwa dia mendengar [Abu Sallam] berkata, telah menceritakan kepada kami [Abu Asma' ar-Rahabi] bahwa [Tsauban, budak Rasulullah Shallallahu'alaihiwasallam] bercerita kepadanya, dia berkata, \"Aku pernah berdiri di dekat Rasulullah Shallallahu'alaihiwasallam, tiba-tiba datanglah salah seorang rahib dari orang-orang Yahudi seraya berkata, 'Semoga keselamatan tercurah atasmu wahai Muhammad. Maka akupun mendorongnya dengan keras hingga dia hampir saja terjungkal karenanya.' Lantas dia bertanya, 'Kenapa kamu mendorongku? ' Aku menjawab, 'Tidak bisakah kamu memanggilnya dengan panggilan \"Rasulullah\"? ' Rahib Yahudi itu menjawab, 'Cukuplah kami memanggilnya dengan nama yang diberikan keluarganya kepadanya.' Lantas Rasulullah shallallahu 'alaihi wasallam berkata, ' namaku ialah Muhammad, nama yang diberikan keluargaku kepadaku.' Yahudi itu berkata, 'Aku datang untuk bertanya beberapa pertanyaan kepadamu.' Rasulullah shallallahu 'alaihi wasallam balik bertanya, 'Adakah sesuatu yang bermanfaat bagimu jika aku berbicara denganmu.' Dia menjawab, 'Aku akan mendengarkan dengan kedua telingaku ini'. Lalu Rasulullah shallallahu 'alaihi wasallam membuat garis-garis ke tanah dengan tongkat yang ada di tangan beliau seraya berkata, 'Bertanyalah! ' Yahudi itu berucap, '(Hari ketika bumi diganti dengan bumi dan langit yang lain…) (QS. Ibrahim 48), kala itu manusia berada di mana? ' Rasulullah shallallahu 'alaihi wasallam menjawab, 'Mereka berada dalam kegelapan di bawah shirath (jembatan).' Dia bertanya, 'Lalu siapakah orang yang paling pertama diizinkan untuk menyeberangi jembatan itu? ' Beliau menjawab, 'Orang-orang fakir dari kaum Muhajirin'. Yahudi itu bertanya lagi, 'Apa hidangan spesial bagi mereka ketika memasuki surga? ' Beliau menjawab, 'Organ yang paling bagus dari hati ikan hiu'. Dia bertanya lagi, 'Setelah itu hidangan apa lagi yang disuguhkan untuk mereka? ' Beliau menjawab, 'Mereka disembelihkan sapi surga yang dimakan dari sisi-sisinya'. Dia bertanya lagi, 'Apa minuman mereka? ' Beliau menjawab, 'Minuman yang diambil dari mata air yang bernama Salsabila'. Dia berkata, 'Kamu benar'. Kemudian dia melanjutkan ucapannya, 'Aku juga datang untuk mengajukan beberapa pertanyaan yang jawabannya tidak diketahui seorang pun di muka bumi ini kecuali seorang Nabi atau seorang atau dua orang lelaki saja'. Beliau berkata, 'Apakah akan memberikan manfaat kepadamu jika aku menjawabnya? ' Dia menjawab, 'Aku akan mendengarkannya dengan kedua telingaku'. Dia berkata, 'Aku datang dengan sebuah pertanyaan mengenai anak'. Beliau menjawab, 'Air mani seorang lelaki berwarna putih dan air mani seorang wanita berwarna kuning, jika keduanya menyatu lalu air mani si lelaki lebih dominan atas air mani wanita maka janin itu akan berkelamin laki-laki dengan izin Allah. Namun jika air mani wanita lebih dominan atas air mani si lelaki maka janin itu akan berkelamin wanita dengan izin Allah.' Yahudi itu berkata, 'Kamu benar, dan kamu memang benar-benar seorang Nabi'. Lalu lelaki Yahudi itupun beranjak pergi. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda, 'Sungguh aku pernah ditanya seseorang tentang pertanyaan yang dia juga menanyakannya kepadaku, dan aku sama sekali tidak tahu jawabannya sampai Allah memberitahukannya kepadaku'. [Abdullah bin Abdurrahman ad-Darimi] memberitahukan hadits ini kepadaku, [Yahya bin Hassan] mengkabarkan kepada kami, [Mu'awiyah bin Sallam] menceritakan seperti itu kepada kami dengan sanad yang sama, tapi bedanya; ia mengatakan: aku pernah duduk di dekat Rasulullah Shallallahu'alaihiwasallam. Dan perbedaan lafadz; \"Zaidatu kabidin nun\" (hati ikan hiu), \"adzkara\" dan \"ânatsa\" (dengan bentuk mufrad/tunggal), dan bukan \"adzkarâ\" dan \"ânatsâ\" (dengan bentuk mutsanna)."},{"p":"Muslim","n":4641,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ عَزَّ وَجَلَّ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَاوَاتُ }فَأَيْنَ يَكُونُ النَّاسُ يَوْمَئِذٍ يَا رَسُولَ اللَّهِ فَقَالَ عَلَى الصِّرَاطِ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Ali bin Mushir] dari [Dawud] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Azza Wa Jalla: 'Pada hari (ketika) bumi diganti dengan bumi yang lain dan begitu pula langit……' (QS. Ibrahim (14): 48), maka dimanakah umat manusia ketika itu, ya Rasulullah?\" Jawab beliau: 'Di Titian (shirath)! '"}]},"mapping_surah":[{"p":"Abu Dawud","n":3972,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُسْلِمَ إِذَا سُئِلَ فِي الْقَبْرِ فَشَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }","trj":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Alqamah bin Martsad] dari [Sa'd bin Ubaidah] dari [Al Bara bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang muslim ditanya dalam kubur, lalu ia bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, dan Muhammad shallallahu 'alaihi wasallam adalah utusan Allah. Maka itu adalah bukti dari firman Allah Azza Wa Jalla: (Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh…) -Qs. Ibrahim: 27-"},{"p":"Abu Dawud","n":3974,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَهَذَا لَفْظُ هَنَّادٍ عَنْ الْأَعْمَشِ عَنْ الْمِنْهَالِ عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةِ رَجُلٍ مِنْ الْأَنْصَارِ فَانْتَهَيْنَا إِلَى الْقَبْرِ وَلَمَّا يُلْحَدْ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَلَسْنَا حَوْلَهُ كَأَنَّمَا عَلَى رُءُوسِنَا الطَّيْرُ وَفِي يَدِهِ عُودٌ يَنْكُتُ بِهِ فِي الْأَرْضِ فَرَفَعَ رَأْسَهُ فَقَالَ اسْتَعِيذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ مَرَّتَيْنِ أَوْ ثَلَاثًا زَادَ فِي حَدِيثِ جَرِيرٍ هَاهُنَا وَقَالَ وَإِنَّهُ لَيَسْمَعُ خَفْقَ نِعَالِهِمْ إِذَا وَلَّوْا مُدْبِرِينَ حِينَ يُقَالُ لَهُ يَا هَذَا مَنْ رَبُّكَ وَمَا دِينُكَ وَمَنْ نَبِيُّكَ قَالَ هَنَّادٌ قَالَ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ دِينِيَ الْإِسْلَامُ فَيَقُولَانِ لَهُ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ قَالَ فَيَقُولُ هُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولَانِ وَمَا يُدْرِيكَ فَيَقُولُ قَرَأْتُ كِتَابَ اللَّهِ فَآمَنْتُ بِهِ وَصَدَّقْتُ زَادَ فِي حَدِيثِ جَرِيرٍ فَذَلِكَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }الْآيَةُ ثُمَّ اتَّفَقَا قَالَ فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ قَدْ صَدَقَ عَبْدِي فَأَفْرِشُوهُ مِنْ الْجَنَّةِ وَافْتَحُوا لَهُ بَابًا إِلَى الْجَنَّةِ وَأَلْبِسُوهُ مِنْ الْجَنَّةِ قَالَ فَيَأْتِيهِ مِنْ رَوْحِهَا وَطِيبِهَا قَالَ وَيُفْتَحُ لَهُ فِيهَا مَدَّ بَصَرِهِ قَالَ وَإِنَّ الْكَافِرَ فَذَكَرَ مَوْتَهُ قَالَ وَتُعَادُ رُوحُهُ فِي جَسَدِهِ وَيَأْتِيهِ مَلَكَانِ فَيُجْلِسَانِهِ فَيَقُولَانِ لَهُ مَنْ رَبُّكَ فَيَقُولُ هَاهْ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ لَهُ مَا دِينُكَ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيَقُولَانِ مَا هَذَا الرَّجُلُ الَّذِي بُعِثَ فِيكُمْ فَيَقُولُ هَاهْ هَاهْ لَا أَدْرِي فَيُنَادِي مُنَادٍ مِنْ السَّمَاءِ أَنْ كَذَبَ فَأَفْرِشُوهُ مِنْ النَّارِ وَأَلْبِسُوهُ مِنْ النَّارِ وَافْتَحُوا لَهُ بَابًا إِلَى النَّارِ قَالَ فَيَأْتِيهِ مِنْ حَرِّهَا وَسَمُومِهَا قَالَ وَيُضَيَّقُ عَلَيْهِ قَبْرُهُ حَتَّى تَخْتَلِفَ فِيهِ أَضْلَاعُهُ زَادَ فِي حَدِيثِ جَرِيرٍ قَالَ ثُمَّ يُقَيَّضُ لَهُ أَعْمَى أَبْكَمُ مَعَهُ مِرْزَبَّةٌ مِنْ حَدِيدٍ لَوْ ضُرِبَ بِهَا جَبَلٌ لَصَارَ تُرَابًا قَالَ فَيَضْرِبُهُ بِهَا ضَرْبَةً يَسْمَعُهَا مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ إِلَّا الثَّقَلَيْنِ فَيَصِيرُ تُرَابًا قَالَ ثُمَّ تُعَادُ فِيهِ الرُّوحُحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا الْمِنْهَالُ عَنْ أَبِي عُمَرَ زَاذَانَ قَالَ سَمِعْتُ الْبَرَاءَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hannad As Sari] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] - dan ini adalah lafadz Hannad- dari [Al A'masy] dari [Al Minhal] dari [Zadzan] dari [Al Bara bin Azib] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam keluar untuk melihat jenazah seorang laki-laki Anshar, kami pun tiba di pemakaman. Ketika lubang lahad telah dibuat, Rasulullah shallallahu 'alaihi wasallam duduk, lalu kami ikut duduk di sisinya. Kami diam, seakan-akan di atas kepala kami ada burung. Saat itu beliau memegang sebatang kayu yang ditancapkan ke dalam tanah, beliau lalu mengangkat kepalanya dan bersabda: \"Mintalah perlindungan kepada Allah dari siksa kubur.\" Beliau ucapkan kalimat itu hingga dua atau tiga kali. Demikanlah tambahan dalam hadits Jarir. Beliau melanjutkan: \"Sungguh, mayat itu akan dapat mendengar derap sandal mereka saat berlalau pulang; yakni ketika ditanyakan kepadanya, 'Wahai kamu, siapa Rabbmu? Apa agamamu? Dan siapa Nabimu? ' -Hannad menyebutkan; Beliau bersabda: - \"lalu ada dua malaikat mendatanginya seranya mendudukkannya. Malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Rabbku adalah Allah.\" Malaikat itu bertanya lagi, \"Apa agamamu?\" ia menjawab, \"Agamaku adalah Islam.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Dia adalah Rasulullah shallallahu 'alaihi wasallam.\" malaikat itu bertanya lagi, \"Apa yang kamu ketahui?\" ia menjawab, \"Aku membaca Kitabullah, aku mengimaninya dan membenarkannya.\" Dalam hadits Jarir ditambahkan, \"Maka inilah makna firman Allah: '(Allah meneguhkan (iman) orang-orang yang beriman…) ' hingga akhir ayat. -Qs. Ibrahim: 27- kemudian kedua perawi sepakat pada lafadz, \"Beliau bersabda: \"Kemudian ada suara dari langit yang menyeru, \"Benarlah apa yang dikatakan oleh hamba-Ku, hamparkanlah permadani untuknya di surga, bukakan baginya pintu-pintu surga dan berikan kepadanya pakaian surga.\" beliau melanjutkan: \"Kemudian didatangkan kepadanya wewangian surga, lalu kuburnya diluaskan sejauh mata memandang.\" Beliau melanjutkan: \"Jika yang meninggal adalah orang kafir, maka ruhnya akan dikembalikan kepada jasadnya. Saat itu datanglah dua malaikat serya mendudukkannya. Kedua malaikat itu bertanya, \"Siapa Rabbmu?\" ia menjawab, \"Hah, hah, hah. Aku tidak tahu.\" Malaikat itu bertanya, \"Apa agamamu?\" ia menjawab, \"Hah, hah. Aku tidak tahu.\" Malaikat itu bertanya lagi, \"Siapa laki-laki yang diutus kepada kalian ini? ' ia menjawab, \"Hah, hah. Aku tidak tahu.\" Setelah itu terdengar suara dari langit: \"Ia telah berdusta. Berilah ia hamparan permadani dari neraka, berikan pakaian dari neraka, dan bukakanlah pintu-pintu neraka untuknya.\" Beliau melanjutkan: \"Kemudian didatangkan kepadanya panas dan baunya neraka. Lalu kuburnya disempitkan hingga tulangnya saling berhimpitan.\" Dalam hadits Jarir ditambahkan, \"Beliau bersabda: \"Lalu ia dibelenggu dalam keadaan buta dan bisu. Dan baginya disediakan sebuah pemukul dari besi, sekiranya pemukul itu dipukulkan pada sebuah gunung niscaya akan menjadi debu.\" Beliau melanjutkan: \"Laki-laki kafir itu kemudian dipukul dengan pemukul tersebut hingga suaranya dapat didengar oleh semua makhluk; dari ujung timur hingga ujung barat -kecuali jin dan manusia- hingga menjadi debu.\" Beliau meneruskan ceritanya: \"Setelah itu, ruhnya dikembalikan lagi.\" Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada kami [Al Minhal] dari [Abu Umar Zadzan] ia berkata; Aku mendengar [Al Bara] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda…. lalu ia menyebutkan seperti hadits tersebut.\""},{"p":"Ahmad","n":2105,"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ عَلْقَمَةُ بْنُ مَرْثَدٍ قَالَ أَخْبَرَنِي عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنِ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْقَبْرِ إِذَا سُئِلَ فَعَرَفَ رَبَّهُ قَالَ وَقَالَ شَيْءٌ لَا أَحْفَظُهُ فَذَلِكَ قَوْلُهُ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] ia berkata, [Alqamah bin Martsad], ia berkata; telah mengabarkan kepadaku dari [Sa'ad bin Ubaidah] dari [Al Baraa` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam bersabda berkenaan dengan kubur: \"Jika seorang hamba ditanya, kemudian ia mengetahui Rabb-nya, -kemudian beliau mengatakan sesuatu namun saya tidak menghafalnya- dan itulah yang termaktub dalam firman Allah: 'Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat. (QS. Ibrahim 27).'\""},{"p":"Ahmad","n":2921,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْجَعْفِيُّ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ تَبَارَكَ وَتَعَالَى{ وَذَكِّرْهُمْ بِأَيَّامِ اللَّهِ }قَالَ بِنِعَمِ اللَّهِ تَبَارَكَ وَتَعَالَىحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيٍّ نَحْوَهُ وَلَمْ يَرْفَعْهُ","trj":"Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Yahya bin Abdullah] mantan budak Bani Hasim, telah meriwayatkan kepada kami [Muhammad bin Aban Al Ja'fi] dari [Abu lshaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, tentang firman Allah Tabaaraka Wa Ta'ala: '(dan ingatkanlah mereka kepada hari-hari Allah) ' (QS Ibrahim: 5) beliau bersabda: \"Yaitu dengan nikmat-nikmat Allah Tabaaraka Wa Ta'ala.\" Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Abu Abdullah Al Anbari] dia berkata, telah menceritakan kepada kami [Abul Walid At Thayalisi] dia berkata, telah menceritakan kepada kami [Muhammad bin Abban] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay] dengan hadits yang semakna, namun ia tidak memarfu'kannya (tidak sampai kepada Nabi).\""},{"p":"Bukhari","n":1280,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقْعِدَ الْمُؤْمِنُ فِي قَبْرِهِ أُتِيَ ثُمَّ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ بِهَذَا وَزَادَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا }نَزَلَتْ فِي عَذَابِ الْقَبْرِ","trj":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'ad bin 'Ubadah] dari [Al Bara' bin 'Azib radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Apabila (jenazah) seorang muslim sudah didudukkan dalam kuburnya maka dia akan dihadapkan (pertanyaan malaikat), kemudian ia bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Allah dan Muhammad utusan Allah. Itulah perkataan seorang muslim sebagaimana firman Allah subhanahu wata'ala (QS Ibrahim ayat 27 yang artinya): (\"Allah akan meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu\"). Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] seperti riwayat ini lalu menambahkannya (firman Allah subhanahu wata'ala): (\"Allah akan meneguhkan (iman) orang-orang yang beriman…\") ayat ini turun berkenaan dengan masalah siksa kubur\"."},{"p":"Ibnu Majah","n":4219,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَنَبِيِّي مُحَمَّدٌ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] darii [Al Barra` bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat; (QS Ibrahim; 27). Beliau bersabda: \"Ayat ini di turunkan mengenai adzab kubur, di katakan kepada mayit; \"Siapa Rabbmu? Maka ia akan menjawab; \"Rabb adalah Allah, dan Nabiku adalah Muhammad.\" dan itulah maksud dari firman-Nya; \" \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat; (QS Ibrahim; 27).\""},{"p":"Ibnu Majah","n":4229,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَاوَاتُ }فَأَيْنَ تَكُونُ النَّاسُ يَوْمَئِذٍ قَالَ عَلَى الصِّرَاطِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Daud] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam (mengenai firman Allah): \"(yaitu) pada hari (ketika) bumi diganti dengan bumi yang lain dan (demikian pula) langit, (QS Ibrahim; 49), lantas di manakah manusia ketika itu?\" Beliau menjawab: \"Di atas shirath.\""},{"p":"Muslim","n":294,"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا قَوْلَ اللَّهِ عَزَّ وَجَلَّ فِي إِبْرَاهِيمَ{ رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِنْ النَّاسِ فَمَنْ تَبِعَنِي فَإِنَّهُ مِنِّي }الْآيَةَ وَقَالَ عِيسَى عَلَيْهِ السَّلَام{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }فَرَفَعَ يَدَيْهِ وَقَالَ اللَّهُمَّ أُمَّتِي أُمَّتِي وَبَكَى فَقَالَ اللَّهُ عَزَّ وَجَلَّ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ وَرَبُّكَ أَعْلَمُ فَسَلْهُ مَا يُبْكِيكَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَسَأَلَهُ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَالَ وَهُوَ أَعْلَمُ فَقَالَ اللَّهُ يَا جِبْرِيلُ اذْهَبْ إِلَى مُحَمَّدٍ فَقُلْ إِنَّا سَنُرْضِيكَ فِي أُمَّتِكَ وَلَا نَسُوءُكَ","trj":"Telah menceritakan kepada kami [Yunus bin Abdul A'la ash-Shadafi] telah mengabarkan kepada kami [Ibnu Wahb] dia berkata, telah mengabarkan kepada kami [Amru bin al-Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya dari [Abdurrahman bin Jubair] dari [Abdullah bin Amr bin al-'Ash] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca firman Allah mengenai Ibrahim: '(Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, Maka Sesungguhnya orang itu termasuk golonganku) ' (Qs. Ibrahim: 36) hingga akhir ayat. Dan mengenai Isa Alaihissalam: '(Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana) ' (Qs. Al Maidah: 118), kemudian beliau mengangkat kedua tangannya seraya berdo'a: \"Ya Allah, selamatkanlah umatku, selamatkanlah umatku, \" dengan bercucuran air mata. Kemudian Allah 'azza wajalla berkata kepada malaikat Jibril: \"Temuilah Muhammad -dan Rabbmulah yang lebih tahu- dan tanyakan kepadanya, 'Apa yang membuatmu menangis? ' Maka malaikat Jibril pun bertanya kepada beliau, dan beliau shallallahu 'alaihi wasallam menjawabnya dengan apa yang dikatakan Allah-dan Allah lebih mengetahui hal itu-. Kemudian Allah berkata: 'Wahai Jibril, temuilah Muhammad dan katakan bahwa Kami akan membuatmu senang dengan umatmu dan tidak akan membuatmu sedih karenanya (Kami akan menyelamatkan semua umatmu-pent) '.\""},{"p":"Muslim","n":465,"ar":"حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ وَهُوَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ يَعْنِي أَخَاهُ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي أَبُو أَسْمَاءَ الرَّحَبِيُّ أَنَّ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ قَالَكُنْتُ قَائِمًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ حِبْرٌ مِنْ أَحْبَارِ الْيَهُودِ فَقَالَ السَّلَامُ عَلَيْكَ يَا مُحَمَّدُ فَدَفَعْتُهُ دَفْعَةً كَادَ يُصْرَعُ مِنْهَا فَقَالَ لِمَ تَدْفَعُنِي فَقُلْتُ أَلَا تَقُولُ يَا رَسُولَ اللَّهِ فَقَالَ الْيَهُودِيُّ إِنَّمَا نَدْعُوهُ بِاسْمِهِ الَّذِي سَمَّاهُ بِهِ أَهْلُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اسْمِي مُحَمَّدٌ الَّذِي سَمَّانِي بِهِ أَهْلِي فَقَالَ الْيَهُودِيُّ جِئْتُ أَسْأَلُكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَنْفَعُكَ شَيْءٌ إِنْ حَدَّثْتُكَ قَالَ أَسْمَعُ بِأُذُنَيَّ فَنَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُودٍ مَعَهُ فَقَالَ سَلْ فَقَالَ الْيَهُودِيُّ أَيْنَ يَكُونُ النَّاسُ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَوَاتُ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ فِي الظُّلْمَةِ دُونَ الْجِسْرِ قَالَ فَمَنْ أَوَّلُ النَّاسِ إِجَازَةً قَالَ فُقَرَاءُ الْمُهَاجِرِينَ قَالَ الْيَهُودِيُّ فَمَا تُحْفَتُهُمْ حِينَ يَدْخُلُونَ الْجَنَّةَ قَالَ زِيَادَةُ كَبِدِ النُّونِ قَالَ فَمَا غِذَاؤُهُمْ عَلَى إِثْرِهَا قَالَ يُنْحَرُ لَهُمْ ثَوْرُ الْجَنَّةِ الَّذِي كَانَ يَأْكُلُ مِنْ أَطْرَافِهَا قَالَ فَمَا شَرَابُهُمْ عَلَيْهِ قَالَ مِنْ عَيْنٍ فِيهَا تُسَمَّى سَلْسَبِيلًا قَالَ صَدَقْتَ قَالَ وَجِئْتُ أَسْأَلُكَ عَنْ شَيْءٍ لَا يَعْلَمُهُ أَحَدٌ مِنْ أَهْلِ الْأَرْضِ إِلَّا نَبِيٌّ أَوْ رَجُلٌ أَوْ رَجُلَانِ قَالَ يَنْفَعُكَ إِنْ حَدَّثْتُكَ قَالَ أَسْمَعُ بِأُذُنَيَّ قَالَ جِئْتُ أَسْأَلُكَ عَنْ الْوَلَدِ قَالَ مَاءُ الرَّجُلِ أَبْيَضُ وَمَاءُ الْمَرْأَةِ أَصْفَرُ فَإِذَا اجْتَمَعَا فَعَلَا مَنِيُّ الرَّجُلِ مَنِيَّ الْمَرْأَةِ أَذْكَرَا بِإِذْنِ اللَّهِ وَإِذَا عَلَا مَنِيُّ الْمَرْأَةِ مَنِيَّ الرَّجُلِ آنَثَا بِإِذْنِ اللَّهِ قَالَ الْيَهُودِيُّ لَقَدْ صَدَقْتَ وَإِنَّكَ لَنَبِيٌّ ثُمَّ انْصَرَفَ فَذَهَبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ سَأَلَنِي هَذَا عَنْ الَّذِي سَأَلَنِي عَنْهُ وَمَا لِي عِلْمٌ بِشَيْءٍ مِنْهُ حَتَّى أَتَانِيَ اللَّهُ بِهِو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ كُنْتُ قَاعِدًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ زَائِدَةُ كَبِدِ النُّونِ وَقَالَ أَذْكَرَ وَآنَثَ وَلَمْ يَقُلْ أَذْكَرَا وَآنَثَا","trj":"Telah menceritakan kepada kami [al-Hasan bin Ali al-Hulwani] telah menceritakan kepada kami [Abu Taubah, yaitu ar-Rabi' bin Nafi'] telah menceritakan kepada kami [Mua'wiyah, yaitu Ibnu Sallam] dari [Zaid, yaitu saudaranya] bahwa dia mendengar [Abu Sallam] berkata, telah menceritakan kepada kami [Abu Asma' ar-Rahabi] bahwa [Tsauban, budak Rasulullah Shallallahu'alaihiwasallam] bercerita kepadanya, dia berkata, \"Aku pernah berdiri di dekat Rasulullah Shallallahu'alaihiwasallam, tiba-tiba datanglah salah seorang rahib dari orang-orang Yahudi seraya berkata, 'Semoga keselamatan tercurah atasmu wahai Muhammad. Maka akupun mendorongnya dengan keras hingga dia hampir saja terjungkal karenanya.' Lantas dia bertanya, 'Kenapa kamu mendorongku? ' Aku menjawab, 'Tidak bisakah kamu memanggilnya dengan panggilan \"Rasulullah\"? ' Rahib Yahudi itu menjawab, 'Cukuplah kami memanggilnya dengan nama yang diberikan keluarganya kepadanya.' Lantas Rasulullah shallallahu 'alaihi wasallam berkata, ' namaku ialah Muhammad, nama yang diberikan keluargaku kepadaku.' Yahudi itu berkata, 'Aku datang untuk bertanya beberapa pertanyaan kepadamu.' Rasulullah shallallahu 'alaihi wasallam balik bertanya, 'Adakah sesuatu yang bermanfaat bagimu jika aku berbicara denganmu.' Dia menjawab, 'Aku akan mendengarkan dengan kedua telingaku ini'. Lalu Rasulullah shallallahu 'alaihi wasallam membuat garis-garis ke tanah dengan tongkat yang ada di tangan beliau seraya berkata, 'Bertanyalah! ' Yahudi itu berucap, '(Hari ketika bumi diganti dengan bumi dan langit yang lain…) (QS. Ibrahim 48), kala itu manusia berada di mana? ' Rasulullah shallallahu 'alaihi wasallam menjawab, 'Mereka berada dalam kegelapan di bawah shirath (jembatan).' Dia bertanya, 'Lalu siapakah orang yang paling pertama diizinkan untuk menyeberangi jembatan itu? ' Beliau menjawab, 'Orang-orang fakir dari kaum Muhajirin'. Yahudi itu bertanya lagi, 'Apa hidangan spesial bagi mereka ketika memasuki surga? ' Beliau menjawab, 'Organ yang paling bagus dari hati ikan hiu'. Dia bertanya lagi, 'Setelah itu hidangan apa lagi yang disuguhkan untuk mereka? ' Beliau menjawab, 'Mereka disembelihkan sapi surga yang dimakan dari sisi-sisinya'. Dia bertanya lagi, 'Apa minuman mereka? ' Beliau menjawab, 'Minuman yang diambil dari mata air yang bernama Salsabila'. Dia berkata, 'Kamu benar'. Kemudian dia melanjutkan ucapannya, 'Aku juga datang untuk mengajukan beberapa pertanyaan yang jawabannya tidak diketahui seorang pun di muka bumi ini kecuali seorang Nabi atau seorang atau dua orang lelaki saja'. Beliau berkata, 'Apakah akan memberikan manfaat kepadamu jika aku menjawabnya? ' Dia menjawab, 'Aku akan mendengarkannya dengan kedua telingaku'. Dia berkata, 'Aku datang dengan sebuah pertanyaan mengenai anak'. Beliau menjawab, 'Air mani seorang lelaki berwarna putih dan air mani seorang wanita berwarna kuning, jika keduanya menyatu lalu air mani si lelaki lebih dominan atas air mani wanita maka janin itu akan berkelamin laki-laki dengan izin Allah. Namun jika air mani wanita lebih dominan atas air mani si lelaki maka janin itu akan berkelamin wanita dengan izin Allah.' Yahudi itu berkata, 'Kamu benar, dan kamu memang benar-benar seorang Nabi'. Lalu lelaki Yahudi itupun beranjak pergi. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda, 'Sungguh aku pernah ditanya seseorang tentang pertanyaan yang dia juga menanyakannya kepadaku, dan aku sama sekali tidak tahu jawabannya sampai Allah memberitahukannya kepadaku'. [Abdullah bin Abdurrahman ad-Darimi] memberitahukan hadits ini kepadaku, [Yahya bin Hassan] mengkabarkan kepada kami, [Mu'awiyah bin Sallam] menceritakan seperti itu kepada kami dengan sanad yang sama, tapi bedanya; ia mengatakan: aku pernah duduk di dekat Rasulullah Shallallahu'alaihiwasallam. Dan perbedaan lafadz; \"Zaidatu kabidin nun\" (hati ikan hiu), \"adzkara\" dan \"ânatsa\" (dengan bentuk mufrad/tunggal), dan bukan \"adzkarâ\" dan \"ânatsâ\" (dengan bentuk mutsanna)."},{"p":"Muslim","n":4641,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ عَزَّ وَجَلَّ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَاوَاتُ }فَأَيْنَ يَكُونُ النَّاسُ يَوْمَئِذٍ يَا رَسُولَ اللَّهِ فَقَالَ عَلَى الصِّرَاطِ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Ali bin Mushir] dari [Dawud] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Azza Wa Jalla: 'Pada hari (ketika) bumi diganti dengan bumi yang lain dan begitu pula langit……' (QS. Ibrahim (14): 48), maka dimanakah umat manusia ketika itu, ya Rasulullah?\" Jawab beliau: 'Di Titian (shirath)! '"},{"p":"Nasa'i","n":1984,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ خَيْثَمَةَ عَنْ الْبَرَاءِ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [bapaknya] dari [Khaitsamah] dari [Al Barra'] dia berkata; \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Dia berkata; 'Ayat ini turun menerangkan tentang siksa kubur.'"},{"p":"Nasa'i","n":1985,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ يُقَالُ لَهُ مَنْ رَبُّكَ فَيَقُولُ رَبِّيَ اللَّهُ وَدِينِي دِينُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","trj":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sa'd bin 'Ubaidah] dari [Al Barra' bin 'Azib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27). Beliau bersabda: 'Ayat ini turun menerangkan tentang siksa kubur.' Dikatakan kepadanya; \"Siapakah Rabbmu?\" lalu ia menjawab, \"Rabbku Allah dan agamaku adalah agamanya Nabi Muhammad shallallahu 'alaihi wasallam.\" Maka itulah yang sesuai dengan firman-Nya, \"Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Qs. Ibrahim 14: 27)"}]};
